import{c as a,Z as i,Q as o,j as r,m as n,o as s}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"Async Payments","description":"","frontmatter":{},"headers":[],"relativePath":"async-payments.md","filePath":"async-payments.md","lastUpdated":1782480285000}'),c={name:"async-payments.md"};function l(d,e,h,p,f,g){const t=i("AsyncPaymentsSequenceDiagram");return o(),r("div",null,[e[0]||(e[0]=n('<h1 id="async-payments" tabindex="-1">Async Payments <a class="header-anchor" href="#async-payments" aria-label="Permalink to &quot;Async Payments&quot;">​</a></h1><p>Async payments let an often-offline node — typically a mobile wallet — receive Lightning payments without keeping an app open in the foreground, without trusting a third party to custody funds, and without anyone encumbering network capacity with long-lived HTLCs.</p><div class="warning custom-block"><p class="custom-block-title">Beta</p><p>Async payments are still under active development and are not yet recommended for production use. In particular, the sender-side HTLC hold — extending CLTVs so the sender&#39;s LSP can hold the payment until the recipient comes online (step 2, &quot;Lock the payment on hold&quot;) — has not yet been merged. The flow currently works LDK-to-LDK only; interoperability with other Lightning implementations is not yet guaranteed, and the APIs described below may change before the feature is complete.</p></div><p>This guide covers how to enable async payments in your application. For the protocol background, the existing approaches it improves on, and the design rationale, see the blog post <a href="/blog/async-payments-receiving-while-offline">Async Payments: Getting Paid While Your Node Is Offline</a>.</p>',4)),s(t),e[1]||(e[1]=n('<h2 id="integrating-async-payments" tabindex="-1">Integrating Async Payments <a class="header-anchor" href="#integrating-async-payments" aria-label="Permalink to &quot;Integrating Async Payments&quot;">​</a></h2><p>LDK handles the async offer machinery transparently once your node is configured for the appropriate role. The configuration differs depending on whether your node is an always-online participant, an often-offline sender or receiver, or the always-online LSP and static-invoice server that supports offline recipients.</p><h3 id="always-online-sender-or-receiver" tabindex="-1">Always-online sender or receiver <a class="header-anchor" href="#always-online-sender-or-receiver" aria-label="Permalink to &quot;Always-online sender or receiver&quot;">​</a></h3><p>If your node is reliably online, no special configuration is required. Pay an offer with <a href="https://docs.rs/lightning/*/lightning/ln/channelmanager/struct.ChannelManager.html#method.pay_for_offer" target="_blank" rel="noreferrer"><code>ChannelManager::pay_for_offer</code></a>; async offers are handled transparently.</p><h3 id="often-offline-sender-or-receiver" tabindex="-1">Often-offline sender or receiver <a class="header-anchor" href="#often-offline-sender-or-receiver" aria-label="Permalink to &quot;Often-offline sender or receiver&quot;">​</a></h3><p>For a node that is frequently offline, such as a mobile wallet:</p><ol><li>Set <a href="https://docs.rs/lightning/*/lightning/util/config/struct.UserConfig.html" target="_blank" rel="noreferrer"><code>UserConfig::enable_htlc_hold</code></a> to <code>true</code>.</li><li>Obtain blinded paths to your static-invoice server out-of-band from the LSP (see <a href="#acting-as-an-lsp-static-invoice-server">Acting as an LSP</a> below).</li><li>Register those paths with <code>ChannelManager::set_paths_to_static_invoice_server</code>.</li><li>When sharing an offer with a sender, obtain it from <code>ChannelManager::get_async_receive_offer</code>.</li><li>Pay offers with <a href="https://docs.rs/lightning/*/lightning/ln/channelmanager/struct.ChannelManager.html#method.pay_for_offer" target="_blank" rel="noreferrer"><code>ChannelManager::pay_for_offer</code></a>; async offers are handled transparently.</li></ol><h3 id="acting-as-an-lsp-static-invoice-server" tabindex="-1">Acting as an LSP / static-invoice server <a class="header-anchor" href="#acting-as-an-lsp-static-invoice-server" aria-label="Permalink to &quot;Acting as an LSP / static-invoice server&quot;">​</a></h3><p>An always-online node that serves offline recipients acts as both an onion message mailbox and a store for static invoices:</p><ol><li>Set <a href="https://docs.rs/lightning/*/lightning/util/config/struct.UserConfig.html" target="_blank" rel="noreferrer"><code>UserConfig::enable_htlc_hold</code></a> to <code>true</code>.</li><li>Initialize the onion messenger with <code>OnionMessenger::new_with_offline_peer_interception</code> so that messages destined for offline peers can be held.</li><li>Generate blinded paths for each recipient with <code>ChannelManager::blinded_paths_for_async_recipient</code> and deliver them to the recipient out-of-band.</li><li>Act as an onion message mailbox by handling <code>Event::OnionMessageIntercepted</code> and <code>Event::OnionMessagePeerConnected</code>: buffer messages for offline peers, and flush them when the peer reconnects.</li><li>Persist static invoices by handling <code>Event::PersistStaticInvoice</code>. Store the provided invoice and blinded path keyed by <code>(recipient_id, invoice_slot)</code>, then call <code>ChannelManager::static_invoice_persisted</code> with the supplied path.</li><li>Serve invoice requests by handling <code>Event::StaticInvoiceRequested</code>. Look up the persisted invoice and reply with <code>ChannelManager::respond_to_static_invoice_request</code>.</li></ol><p>For a complete reference on the events referenced above, see the <a href="https://docs.rs/lightning/*/lightning/events/enum.Event.html" target="_blank" rel="noreferrer"><code>Event</code> documentation</a>. For details on configuring and constructing the <code>ChannelManager</code>, see <a href="/building-a-node-with-ldk/setting-up-a-channel-manager">Setting up a ChannelManager</a>.</p>',11))])}const u=a(c,[["render",l]]);export{m as __pageData,u as default};
